content:
choice = int(input("1: km -> miles, 2: miles -> km: "))
dist = float(input("Enter distance: "))
if choice == 1:
    miles = dist / 1.60934
    print(f"{dist:.2f} km = {miles:.2f} miles.")
elif choice == 2:
    km = dist * 1.60934
    print(f"{dist:.2f} miles = {km:.2f} km.")
else:
    print("Invalid choice.")
